#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $query = CGI->new;
print $query->header('text/html');

my $comment = $query->param('comment') || '';

# Allow basic HTML tags but escape others to prevent XSS
$comment =~ s/</&lt;/g;
$comment =~ s/>/&gt;/g;
$comment =~ s/&lt;(\/?(b|i|u|strong|em|p|br|ul|ol|li|a|blockquote|code|pre|h[1-6]))&gt;/<$1>/g;

print "<div>$comment</div>";